external_knowledge:
External knowledge used:
- 'golden investments' refers to colleges with a predicted ROI > 500,000 and an average actual ROI > 400,000;
- 'stellar' graduation track record means a 6-year graduation rate > 50%;
- 'affordable' education refers to in-state tuition < 20,000 and out-of-state tuition < 40,000;
- 'lucrative' return on investment means an average actual ROI > 400,000.

sql:
SELECT college_type, COUNT(*) AS college_count 
FROM colleges 
GROUP BY college_type;

SELECT AVG(factor_value) AS average_class_size
FROM factors_impacting_success
WHERE factor_name = 'Average Class Size';
